import "../quiz_question.dart";

const _subject = "Yoruba";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// JAMB Yoruba — 100 questions covering Ede (Fonoloji, Girama, Aroko/
/// Ogbufo, Fahimta), Literesọ (oral and written literature), and Asa
/// (beliefs, institutions/rites, values/numerals). Weighted toward
/// well-established culture and oral-literature facts, with the
/// prescribed written texts covered only at general/author level.
List<QuizQuestion> buildJambYorubaQuestions() {
  return [
    ..._fonoloji,
    ..._girama,
    ..._arokoAtiOgbufo,
    ..._fahimta,
    ..._literesoAlenu,
    ..._literesoKiko,
    ..._eroAtiIgbagbo,
    ..._institutionsAtiRites,
    ..._valuesAtiNumerals,
  ];
}

